import React, { useState, useEffect } from 'react';
import api from '../api/axiosConfig';
import { Archive, Calendar, Shield, ExternalLink } from 'lucide-react';

const Vault = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const res = await api.get('/portfolio/history');
        setHistory(res.data);
      } catch (err) {
        console.error("Vault Access Denied", err);
      } finally {
        setLoading(false);
      }
    };
    fetchHistory();
  }, []);

  return (
    <div className="reveal-node" style={{ padding: '2rem', maxWidth: '1000px', margin: '0 auto' }}>
      <h2 style={{ color: 'var(--text-primary)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '10px' }}>
        <Archive size={20} color="var(--accent-primary)" /> Strategy_Vault
      </h2>

      {loading ? (
        <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>DECRYPTING_VAULT_NODES...</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          {history.map((item) => (
            <div key={item.id} style={{ padding: '1.25rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '14px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontSize: '0.8rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '0.2rem' }}>{item.goal}</div>
                <div style={{ fontSize: '0.6rem', color: 'var(--text-muted)', display: 'flex', gap: '1rem' }}>
                  <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Calendar size={10} /> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Shield size={10} color="var(--accent-primary)" /> Risk: {item.risk_score}</span>
                </div>
              </div>
              <button style={{ background: 'transparent', border: '1px solid var(--accent-primary)', padding: '0.4rem', borderRadius: '8px', color: 'var(--accent-primary)', cursor: 'pointer' }}>
                <ExternalLink size={14} />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Vault;
